Rule.Source:
  import sailpoint.tools.Util;
  import sailpoint.object.Identity;
  import sailpoint.object.ManagedAttribute;
  import sailpoint.object.QueryOptions;
  import sailpoint.object.Filter;
  import sailpoint.object.Field;
  import sailpoint.object.ProvisioningPlan.AccountRequest; 
  import sailpoint.object.ProvisioningPlan.AttributeRequest; 
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  Log logger = LogFactory.getLog("rule.Invision.Field.Values");

  logger.debug("Entering RACF-Invision Provisioning Policy Form Rule for field "+field.getName());
  String fieldVal = "";
  String profileCode = "";
  if(accountRequest != null){

    AttributeRequest attrRequest = accountRequest.getAttributeRequest("entitlement");
    if(attrRequest != null && null != attrRequest.getValue()){
      String groupName = attrRequest.getValue();
      if(groupName != null){
        ManagedAttribute existingGroup = null;

        QueryOptions qo = new QueryOptions();
        qo.addFilter(Filter.eq("application", application));
        qo.addFilter(Filter.eq("value", groupName));
        qo.addFilter(Filter.eq("attribute", "entitlement"));

        List foundGroup = context.getObjects(ManagedAttribute.class, qo);
        if (foundGroup.size() == 1) {
          existingGroup = foundGroup.get(0);
        }

        if(existingGroup != null){

          StringTokenizer ministryNameSplit = new StringTokenizer(groupName, "-");
          if(null != ministryNameSplit){
            int count = ministryNameSplit.countTokens(); 
            for (int i = 0; i < count; i++) {
              profileCode = ministryNameSplit.nextToken();
              if (i == 2){
                break;
              }
            }
          }

          String profileName = "Profile"+profileCode.trim();

          if(field.getName().equalsIgnoreCase("CashGrp") && existingGroup.getAttribute(field.getName()) != null){
            fieldVal = existingGroup.getAttribute("CashGrp");
          }
          else if(field.getName().equalsIgnoreCase("MenuGrp") && existingGroup.getAttribute(field.getName()) != null){
            fieldVal = existingGroup.getAttribute(field.getName());
          }
          else if( field.getName().equalsIgnoreCase("PROUT") && existingGroup.getAttribute(field.getName()) != null){
            fieldVal = "1";
          }
          else if(field.getName().equalsIgnoreCase("PRCOL") && existingGroup.getAttribute(field.getName()) != null){
            fieldVal = "1";
          }
          else if(field.getName().equalsIgnoreCase("TCL") && existingGroup.getAttribute(field.getName()) != null){
            fieldVal = existingGroup.getAttribute(field.getName());
          }        
          else if( field.getName().equalsIgnoreCase("Comment2") && existingGroup.getAttribute(field.getName()) != null){
            fieldVal = existingGroup.getAttribute(field.getName());
          }
          else if(groupName.contains("Production") && field.getName().equalsIgnoreCase("Need"+profileCode.trim())){
            fieldVal = "1";
          }
          else if(groupName.contains("Test") && field.getName().equalsIgnoreCase("NeedTest"+profileCode.trim())){
            fieldVal = "1";
          }
          else if (field.getName().contains("Need")){
            fieldVal = "0";
          }
          else if( field.getName().equalsIgnoreCase(profileName) && existingGroup.getAttribute(profileName) != null){

            fieldVal = existingGroup.getAttribute(profileName);
          }
          else if (field.getName().contains("Profile")){
            fieldVal = "";
          }
        }
      }      
    }
  }
  logger.debug("Exiting RACF-Invision Provisioning Policy Form Rule for field "+field.getName());
  return fieldVal;
